#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $cgi = CGI->new;

print $cgi->header('text/html');

my $log_dir = "/path/to/your/log/directory";
my $filename = $cgi->param('logfile');

if ($filename =~ /^([a-zA-Z0-9_.-]+)$/) {
    $filename = $1;
} else {
    die "Invalid filename";
}

open(FH, "<", "$log_dir/$filename") or die "Cannot open file: $!";

while (<FH>) {
    print $cgi->escapeHTML($_) . "<br>";
}

close(FH);